              <p>Phone: ${(P==null?void 0:P.phone_number)||"040 - 68244555, 88012 33333"} &nbsp;|&nbsp; Web: ${(P==null?void 0:P.website)||"https://prasadhospitals.in"} &nbsp;|&nbsp; Email: ${(P==null?void 0:P.email)||"info@prasadhospitals.in"}</p>
